  "inlineSchema": "// This is your Prisma schema file,\n// learn more about it in the docs: https://pris.ly/d/prisma-schema\n// Define database connection via the `DATABASE_URL` env var\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_PRISMA_DATABASE_URL\")\n}\n\n// Define custom output path for generated Prisma Client\ngenerator client {\n  provider = \"prisma-client-js\"\n  output   = \"lib/generated/prisma-client\"\n}\n\n// User model to store Farcaster identity details\nmodel User {\n  id                    String  @id @default(cuid())\n  farcaster_id          String  @unique @db.VarChar(255)\n  farcaster_username    String  @db.VarChar(255)\n  farcaster_pfp         String? @db.Text\n  wallet_address        String? @db.VarChar(42) // Farcaster connected wallet (initial wallet for SIWE)\n  server_wallet_address String? @db.VarChar(42) // Server-side custodial wallet address\n\n  // SIWE Authentication fields\n  siweSignature String?   @map(\"siwe_signature\") @db.Text // SIWE signature authorizing custodial wallet\n  siweMessage   String?   @map(\"siwe_message\") @db.Text // SIWE message that was signed\n  siweExpiresAt DateTime? @map(\"siwe_expires_at\") // Expiration of SIWE authorization\n\n  createdAt DateTime @default(now()) @map(\"created_at\")\n  updatedAt DateTime @updatedAt @map(\"updated_at\")\n\n  wallet   Wallet?\n  bets     Bet[]\n  sessions Session[]\n\n  @@index([farcaster_id])\n  @@index([server_wallet_address])\n  @@map(\"users\")\n}\n\n// Session model for cookie-based authentication\nmodel Session {\n  id        String   @id @default(cuid())\n  userId    String   @map(\"user_id\")\n  expiresAt DateTime @map(\"expires_at\")\n  createdAt DateTime @default(now()) @map(\"created_at\")\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@index([userId])\n  @@index([expiresAt])\n  @@map(\"sessions\")\n}\n\n// Server-side wallet management (separate from Ponder's onchain data)\nmodel Wallet {\n  // Primary identifier (Farcaster FID or other user ID)\n  userId String @id @map(\"user_id\") @db.VarChar(255)\n\n  // Ethereum wallet address\n  address String @unique @db.VarChar(42)\n\n  // Encrypted private key (AES-256-GCM encrypted)\n  encryptedPrivateKey String @map(\"encrypted_private_key\") @db.Text\n\n  // Unix timestamp (milliseconds) when wallet was created\n  createdAt BigInt @map(\"created_at\")\n\n  // Cached balance in wei (as string to handle big numbers)\n  balance String @default(\"0\") @db.VarChar(78)\n\n  // Locked balance (funds committed to pending bets) in wei\n  lockedBalance String @default(\"0\") @map(\"locked_balance\") @db.VarChar(78)\n\n  // Unix timestamp (milliseconds) of last transaction\n  lastUsed BigInt? @map(\"last_used\")\n\n  // Timestamp fields for database management\n  createdAtTimestamp DateTime @default(now()) @map(\"created_at_timestamp\")\n  updatedAt          DateTime @updatedAt @map(\"updated_at\")\n\n  // Relations\n  user         User                @relation(fields: [userId], references: [id], onDelete: Cascade)\n  transactions WalletTransaction[]\n\n  @@index([address])\n  @@index([lastUsed])\n  @@index([createdAt])\n  @@map(\"wallets\")\n}\n\n// NOTE: Ponder manages these tables automatically:\n// - account (onchain accounts)\n// - transfer_event (transfer events)\n// - allowance (token allowances)\n// - approval_event (approval events)\n// - user (onchain user stats)\n// - bet (betting events)\n//\n// We only manage the Wallet table for server-side wallet encryption\n// All betting data comes from Ponder's GraphQL API\n\n// Optional: Transaction history model\n// Uncomment to track transaction history\nmodel WalletTransaction {\n  id          Int       @id @default(autoincrement())\n  userId      String    @map(\"user_id\") @db.VarChar(255)\n  txHash      String?   @map(\"tx_hash\") @db.VarChar(66)\n  txType      String    @map(\"tx_type\") @db.VarChar(50) // 'bet', 'withdraw', 'deposit', 'payout'\n  amount      String    @db.VarChar(78)\n  status      String    @db.VarChar(20) // 'pending', 'confirmed', 'failed'\n  blockNumber BigInt?   @map(\"block_number\")\n  gasUsed     String?   @map(\"gas_used\") @db.VarChar(78)\n  createdAt   DateTime  @default(now()) @map(\"created_at\")\n  confirmedAt DateTime? @map(\"confirmed_at\")\n\n  wallet Wallet @relation(fields: [userId], references: [userId], onDelete: Cascade)\n\n  @@index([userId])\n  @@index([txHash])\n  @@index([createdAt])\n  @@map(\"wallet_transactions\")\n}\n\n// Off-chain provably fair bet storage\nmodel Bet {\n  id               String  @id @default(cuid())\n  userId           String  @map(\"user_id\") @db.VarChar(255)\n  playerId         String  @map(\"player_id\") @db.VarChar(42) // Wallet address (custodial wallet)\n  serverSeedHash   String  @map(\"server_seed_hash\") @db.VarChar(64) // SHA256 commitment\n  serverSeed       String? @map(\"server_seed\") @db.VarChar(64) // Revealed after resolution\n  clientSeed       String? @map(\"client_seed\") @db.VarChar(64) // Optional client seed\n  randomValue      String  @map(\"random_value\") @db.VarChar(64) // SHA256(serverSeed + playerId + betId)\n  gameNumber       String  @map(\"game_number\") @db.VarChar(78) // (BigInt(randomValue) % 1e9) + 1\n  wager            String  @db.VarChar(78) // Bet amount in wei\n  targetMultiplier String  @map(\"target_multiplier\") @db.VarChar(20) // Target multiplier (x100)\n  limboMultiplier  String? @map(\"limbo_multiplier\") @db.VarChar(20) // Actual result multiplier (x100)\n  outcome          String  @db.VarChar(10) // 'win' or 'lose'\n  payout           String  @db.VarChar(78) // Payout amount in wei\n  status           String  @db.VarChar(20) // 'pending', 'processing', 'resolved' (win), 'complete' (loss), 'failed', 'pending_payout'\n\n  // Exchange rate and USD values (for verification)\n  ethPriceUsd String? @map(\"eth_price_usd\") @db.VarChar(20) // ETH/USD price at bet time\n  wagerUsd    String? @map(\"wager_usd\") @db.VarChar(20) // Bet amount in USD\n  payoutUsd   String? @map(\"payout_usd\") @db.VarChar(20) // Payout amount in USD\n\n  // Bet signature for verification (signed by custodial wallet)\n  betSignature String? @map(\"bet_signature\") @db.Text // Signature of bet message\n  betMessage   String? @map(\"bet_message\") @db.Text // Message that was signed (contains betId, wager, multiplier, hash, timestamp)\n\n  signature  String?   @db.Text // Backend signature for payout verification (legacy)\n  txHash     String?   @map(\"tx_hash\") @db.VarChar(66) // Payout transaction hash\n  createdAt  DateTime  @default(now()) @map(\"created_at\")\n  resolvedAt DateTime? @map(\"resolved_at\")\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@index([userId])\n  @@index([playerId])\n  @@index([createdAt])\n  @@index([status])\n  @@map(\"bets\")\n}\n",
